        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        requestBody: {
            content: {
                "application/json": components["schemas"]["VerifyCodeDto"];
            };
        };
        responses: {
            /** @description Step 2: verify the second factor (6-digit TOTP or one-time backup code) ONCE and stamp the challenge (factor_verified_at). On success 200 { status: "code_verified" } — the TOTP replay floor is advanced / the backup code consumed, and the later /verify needs no code. IDEMPOTENT for an already-stamped challenge (a Back/retry does not re-spend the factor). On a bad/expired factor the per-challenge attempt counter advances and 401 Auth.ResetInvalidCode is returned. The verify-code call sets NO cookie and issues NO token. */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["ResetCodeVerifiedResponseDto"];
                };
            };
        };
